        INSERT INTO wordup_entities (type, label, metadata, difficulty, tags) VALUES
        ('english_fundamentals', 'Noun',
         '{"description":"A word that names a person, place, thing, or idea","category":"Parts of Speech","difficulty":1,"popularity":95,"definition":"A noun is a part of speech that functions as the name of a specific entity — a person, place, thing, or abstract idea.","example":"London, desk, teacher","contrast":"Verb","images":[]}',
