        ('english_fundamentals', 'Verb',
         '{"description":"A word that expresses an action, occurrence, or state of being","category":"Parts of Speech","difficulty":1,"popularity":95,"definition":"A verb describes what the subject of a sentence does, what happens to it, or its state of existence.","example":"run, write, exist","contrast":"Noun","images":[]}',
         1, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Adjective',
