         1, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Adverb',
         '{"description":"A word that modifies a verb, adjective, or another adverb","category":"Parts of Speech","difficulty":2,"popularity":85,"definition":"An adverb adds detail about how, when, where, or to what extent an action occurs or a quality exists.","example":"quickly, very, silently","contrast":"Adjective","images":[]}',
