        ('english_fundamentals', 'Conjunction',
         '{"description":"A word that connects words, phrases, or clauses","category":"Parts of Speech","difficulty":2,"popularity":80,"definition":"A conjunction joins linguistic units of equal or unequal rank to form coherent sentences.","example":"and, but, or, because","contrast":"Preposition","images":[]}',
         2, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Interjection',
         '{"description":"A word or phrase that expresses strong emotion or surprise","category":"Parts of Speech","difficulty":1,"popularity":70,"definition":"An interjection is a sudden exclamation that stands alone to convey emotion, greeting, or reaction.","example":"Wow! Ouch! Hey! Oh!","images":[]}',
