         1, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Simple Past',
         '{"description":"A tense used for completed actions at a specific time in the past","category":"Tenses","difficulty":1,"popularity":90,"definition":"The simple past expresses an action that began and ended at a definite time in the past.","example":"They visited the museum yesterday.","contrast":"Present Perfect","images":[]}',
         1, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Simple Future',
         '{"description":"A tense used for actions that will happen later","category":"Tenses","difficulty":2,"popularity":85,"definition":"The simple future expresses predictions, promises, or spontaneous decisions about events yet to occur.","example":"I will call you tomorrow.","contrast":"Future Continuous","images":[]}',
         2, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Present Continuous',
         '{"description":"A tense used for actions happening right now or around the current time","category":"Tenses","difficulty":2,"popularity":85,"definition":"The present continuous describes an ongoing action in progress at the moment of speaking or a temporary situation.","example":"She is reading a book right now.","contrast":"Simple Present","images":[]}',
         2, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Past Continuous',
         '{"description":"A tense used for actions that were ongoing at a specific past moment","category":"Tenses","difficulty":2,"popularity":80,"definition":"The past continuous describes an action that was in progress at a particular time in the past, often interrupted by another event.","example":"I was watching TV when the phone rang.","contrast":"Simple Past","images":[]}',
         2, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Future Continuous',
