         3, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Present Perfect',
         '{"description":"A tense linking past actions to the present moment","category":"Tenses","difficulty":3,"popularity":85,"definition":"The present perfect connects a past action or experience to the present, without specifying exactly when it occurred.","example":"She has visited Japan three times.","contrast":"Simple Past","images":[]}',
         3, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Past Perfect',
         '{"description":"A tense showing that one past action happened before another","category":"Tenses","difficulty":3,"popularity":80,"definition":"The past perfect indicates an action completed before another past action or time.","example":"They had already eaten when I arrived.","contrast":"Present Perfect","images":[]}',
         3, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Future Perfect',
         '{"description":"A tense describing actions that will be completed by a future time","category":"Tenses","difficulty":4,"popularity":70,"definition":"The future perfect expresses an action that will be finished before a specified future moment.","example":"By next month, I will have finished the project.","contrast":"Future Continuous","images":[]}',
         4, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Present Perfect Continuous',
         '{"description":"A tense for actions that started in the past and continue into the present","category":"Tenses","difficulty":4,"popularity":70,"definition":"The present perfect continuous emphasizes the duration of an action that began in the past and is still ongoing.","example":"She has been studying for three hours.","contrast":"Present Perfect","images":[]}',
         4, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Past Perfect Continuous',
         '{"description":"A tense for ongoing past actions that happened before another past event","category":"Tenses","difficulty":4,"popularity":65,"definition":"The past perfect continuous emphasizes the duration of an action that was ongoing before another past event occurred.","example":"They had been waiting for an hour when the bus finally arrived.","contrast":"Past Perfect","images":[]}',
         4, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Future Perfect Continuous',
         '{"description":"A tense for actions that will have been ongoing up to a future point","category":"Tenses","difficulty":5,"popularity":60,"definition":"The future perfect continuous emphasizes the duration of an action that will continue up to a specified future time.","example":"By December, I will have been working here for ten years.","contrast":"Future Perfect","images":[]}',
         5, ARRAY['concept', 'grammar']),

        -- ── GRAMMAR CONCEPTS (14) ───────────────────────────────────────
        ('english_fundamentals', 'Subject',
         '{"description":"The person or thing that performs the action in a sentence","category":"Grammar","difficulty":1,"popularity":90,"definition":"The subject is the noun or pronoun that performs the verb or is described by the sentence.","example":"The cat sat on the mat.","contrast":"Object","images":[]}',
         1, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Predicate',
