         2, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Clause',
         '{"description":"A group of words containing a subject and a predicate","category":"Grammar","difficulty":2,"popularity":75,"definition":"A clause is a grammatical unit with its own subject and verb; it may be independent or dependent.","example":"Although it rained, we still went out.","contrast":"Phrase","images":[]}',
         2, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Phrase',
