         2, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Subject-Verb Agreement',
         '{"description":"The grammatical rule that the subject and verb must match in number","category":"Grammar","difficulty":3,"popularity":85,"definition":"Subject-verb agreement requires a singular subject to take a singular verb and a plural subject to take a plural verb.","example":"She runs fast. They run fast.","images":[]}',
         3, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Active Voice',
         '{"description":"A sentence structure where the subject performs the action","category":"Grammar","difficulty":2,"popularity":80,"definition":"In active voice, the subject acts upon the object, creating a direct and vigorous sentence.","example":"The chef cooked the meal.","contrast":"Passive Voice","images":[]}',
