        ('english_fundamentals', 'Passive Voice',
         '{"description":"A sentence structure where the subject receives the action","category":"Grammar","difficulty":3,"popularity":80,"definition":"In passive voice, the object of an action becomes the subject, and the verb phrase includes a form of ''be'' plus past participle.","example":"The meal was cooked by the chef.","contrast":"Active Voice","images":[]}',
