         3, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Conditional Type 0',
         '{"description":"A conditional expressing general truths or scientific facts","category":"Grammar","difficulty":3,"popularity":70,"definition":"Type 0 conditional uses present tense in both clauses for statements that are always true.","example":"If you heat ice, it melts.","contrast":"Conditional Type 1","images":[]}',
         3, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Conditional Type 1',
