        ('english_fundamentals', 'Parentheses',
         '{"description":"A pair of punctuation marks enclosing additional or explanatory information","category":"Punctuation","difficulty":2,"popularity":75,"definition":"Parentheses enclose supplementary material, clarifications, or asides that are not essential to the main sentence.","example":"He finally arrived (after two hours).","contrast":"Dash","images":[]}',
         2, ARRAY['concept', 'punctuation']),
        ('english_fundamentals', 'Dash',
