         3, ARRAY['concept', 'grammar']),
        ('english_fundamentals', 'Compound-Complex Sentence',
         '{"description":"A sentence with multiple independent clauses and at least one dependent clause","category":"Sentence Structure","difficulty":4,"popularity":70,"definition":"A compound-complex sentence contains at least two independent clauses and one or more dependent clauses.","example":"Although I was tired, I finished my work, and then I went to bed.","contrast":"Complex Sentence","images":[]}',
         4, ARRAY['concept', 'grammar']),
