        -- ── LITERARY DEVICES (16) ────────────────────────────────────────
        ('english_fundamentals', 'Metaphor',
         '{"description":"A direct comparison of two unlike things without using like or as","category":"Literary Device","difficulty":2,"popularity":90,"definition":"A metaphor asserts that one thing is another to create a vivid comparison or implied analogy.","example":"Time is a thief.","contrast":"Simile","images":[]}',
         2, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Simile',
         '{"description":"A comparison of two unlike things using like or as","category":"Literary Device","difficulty":2,"popularity":90,"definition":"A simile explicitly compares two different things using the words ''like'' or ''as'' to create imagery.","example":"As brave as a lion.","contrast":"Metaphor","images":[]}',
         2, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Alliteration',
         '{"description":"The repetition of initial consonant sounds in nearby words","category":"Literary Device","difficulty":2,"popularity":85,"definition":"Alliteration repeats the same sound at the beginning of adjacent or closely connected words for rhythmic effect.","example":"Peter Piper picked a peck of pickled peppers.","contrast":"Assonance","images":[]}',
         2, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Personification',
         '{"description":"Giving human qualities to non-human things or abstract ideas","category":"Literary Device","difficulty":2,"popularity":85,"definition":"Personification attributes human characteristics, emotions, or actions to inanimate objects or abstract concepts.","example":"The wind whispered through the trees.","contrast":"Metaphor","images":[]}',
         2, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Hyperbole',
         '{"description":"An extreme exaggeration used for emphasis or effect","category":"Literary Device","difficulty":2,"popularity":85,"definition":"Hyperbole deliberately exaggerates beyond reality to create strong feeling or humorous effect.","example":"I am so hungry I could eat a horse.","contrast":"Understatement","images":[]}',
         2, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Onomatopoeia',
         '{"description":"A word that phonetically imitates the sound it describes","category":"Literary Device","difficulty":2,"popularity":80,"definition":"Onomatopoeia uses words whose pronunciation mimics the natural sound of the thing they describe.","example":"buzz, crash, hiss, boom","contrast":"Alliteration","images":[]}',
         2, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Irony',
         '{"description":"The expression of meaning through language that signifies the opposite","category":"Literary Device","difficulty":3,"popularity":85,"definition":"Irony creates a contrast between what is said and what is actually meant or between expectation and reality.","example":"A fire station burning down.","contrast":"Sarcasm","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Foreshadowing',
         '{"description":"A hint or clue about events that will happen later in a story","category":"Literary Device","difficulty":3,"popularity":80,"definition":"Foreshadowing plants subtle hints or warnings about future plot developments.","example":"A character noticing a broken clock before a time-related tragedy.","contrast":"Flashback","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Flashback',
         '{"description":"An interruption that transports the narrative to an earlier time","category":"Literary Device","difficulty":3,"popularity":80,"definition":"A flashback breaks the chronological flow to show events that occurred before the current story timeline.","example":"A character remembering their childhood during a crisis.","contrast":"Foreshadowing","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Symbolism',
         '{"description":"The use of symbols to represent ideas or qualities beyond their literal meaning","category":"Literary Device","difficulty":3,"popularity":85,"definition":"Symbolism imbues objects, characters, or colors with deeper abstract meanings.","example":"A dove representing peace.","contrast":"Imagery","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Imagery',
         '{"description":"Vivid descriptive language that appeals to the senses","category":"Literary Device","difficulty":2,"popularity":85,"definition":"Imagery uses sensory details to create vivid mental pictures for the reader.","example":"The golden sand stretched endlessly under the blazing sun.","contrast":"Symbolism","images":[]}',
         2, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Oxymoron',
         '{"description":"A figure of speech combining contradictory terms","category":"Literary Device","difficulty":3,"popularity":75,"definition":"An oxymoron places two opposite or contradictory words together for rhetorical effect.","example":"deafening silence, jumbo shrimp","contrast":"Paradox","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Paradox',
         '{"description":"A seemingly contradictory statement that reveals a hidden truth","category":"Literary Device","difficulty":4,"popularity":75,"definition":"A paradox appears self-contradictory but upon reflection contains a deeper layer of meaning.","example":"I must be cruel to be kind.","contrast":"Oxymoron","images":[]}',
         4, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Allusion',
         '{"description":"An indirect reference to a person, event, or work of art","category":"Literary Device","difficulty":4,"popularity":70,"definition":"An allusion briefly and indirectly references a well-known figure, event, or cultural work.","example":"He had a Herculean task ahead.","contrast":"Metaphor","images":[]}',
         4, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Assonance',
         '{"description":"The repetition of vowel sounds in nearby words","category":"Literary Device","difficulty":3,"popularity":65,"definition":"Assonance repeats identical or similar vowel sounds in stressed syllables of adjacent words for internal rhyme.","example":"The rain in Spain falls mainly on the plain.","contrast":"Alliteration","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Consonance',
         '{"description":"The repetition of consonant sounds within or at the end of words","category":"Literary Device","difficulty":3,"popularity":60,"definition":"Consonance repeats consonant sounds in nearby words, often at the end of stressed syllables.","example":"pitter patter, last but not least","contrast":"Assonance","images":[]}',
         3, ARRAY['concept', 'literary-devices']),

        -- ── WORD FORMATION (8) ────────────────────────────────────────────
        ('english_fundamentals', 'Prefix',
         '{"description":"An affix placed before a root word to modify its meaning","category":"Word Formation","difficulty":2,"popularity":80,"definition":"A prefix is a group of letters added to the beginning of a base word to create a new meaning.","example":"un- in unhappy, re- in rewrite","contrast":"Suffix","images":[]}',
         2, ARRAY['concept', 'vocabulary']),
        ('english_fundamentals', 'Suffix',
         '{"description":"An affix placed after a root word to change its meaning or grammatical function","category":"Word Formation","difficulty":2,"popularity":80,"definition":"A suffix is added to the end of a word to alter its meaning or part of speech.","example":"-ly in quickly, -ness in kindness","contrast":"Prefix","images":[]}',
         2, ARRAY['concept', 'vocabulary']),
        ('english_fundamentals', 'Root Word',
         '{"description":"The core part of a word carrying its primary meaning","category":"Word Formation","difficulty":2,"popularity":75,"definition":"A root word is the basic lexical unit of a word, from which related words are formed by adding affixes.","example":"struct in construct, destroy, structure","contrast":"Prefix","images":[]}',
         2, ARRAY['concept', 'vocabulary']),
        ('english_fundamentals', 'Compound Word',
         '{"description":"A word formed by combining two or more independent words","category":"Word Formation","difficulty":2,"popularity":80,"definition":"A compound word joins two separate words to create a new word with its own meaning.","example":"notebook, toothpaste, bedroom","contrast":"Blend","images":[]}',
         2, ARRAY['concept', 'vocabulary']),
        ('english_fundamentals', 'Blend',
         '{"description":"A word formed by merging parts of two words","category":"Word Formation","difficulty":3,"popularity":70,"definition":"A blend (portmanteau) combines parts of two words to create a new term that retains aspects of both meanings.","example":"brunch (breakfast + lunch), smog (smoke + fog)","contrast":"Compound Word","images":[]}',
         3, ARRAY['concept', 'vocabulary']),
        ('english_fundamentals', 'Acronym',
         '{"description":"A word formed from the initial letters of a phrase","category":"Word Formation","difficulty":2,"popularity":85,"definition":"An acronym is pronounced as a word and formed from the first letters of a multi-word name.","example":"NASA, radar, AIDS","contrast":"Abbreviation","images":[]}',
         2, ARRAY['concept', 'vocabulary']),
        ('english_fundamentals', 'Abbreviation',
         '{"description":"A shortened form of a word or phrase","category":"Word Formation","difficulty":1,"popularity":80,"definition":"An abbreviation represents a longer word or phrase by omitting some letters, often ending with a period.","example":"Dr. for Doctor, etc. for et cetera","contrast":"Acronym","images":[]}',
         1, ARRAY['concept', 'vocabulary']),
        ('english_fundamentals', 'Contraction',
         '{"description":"A shortened word combining two words with omitted letters","category":"Word Formation","difficulty":1,"popularity":85,"definition":"A contraction combines two words by dropping letters and replacing them with an apostrophe.","example":"don''t, can''t, I''m, you''re","contrast":"Abbreviation","images":[]}',
         1, ARRAY['concept', 'vocabulary']),

        -- ── COMMON ERRORS (12) ────────────────────────────────────────────
        ('english_fundamentals', 'There/Their/They''re',
         '{"description":"A set of homophones commonly confused in writing","category":"Common Errors","difficulty":2,"popularity":90,"definition":"''There'' refers to a place, ''their'' shows possession, and ''they''re'' is a contraction of ''they are''.","example":"There is their house. They''re happy.","images":[]}',
         2, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Your/You''re',
         '{"description":"A pair of homophones frequently misused in writing","category":"Common Errors","difficulty":1,"popularity":90,"definition":"''Your'' indicates possession, while ''you''re'' is the contraction of ''you are''.","example":"You''re going to love your new car.","images":[]}',
         1, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Its/It''s',
         '{"description":"A pair of homophones that often cause confusion","category":"Common Errors","difficulty":2,"popularity":85,"definition":"''Its'' is the possessive form of ''it'', while ''it''s'' is the contraction of ''it is'' or ''it has''.","example":"It''s raining, so bring its leash.","images":[]}',
         2, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Affect/Effect',
         '{"description":"Verb and noun pair with distinct meanings often swapped","category":"Common Errors","difficulty":3,"popularity":80,"definition":"''Affect'' is usually a verb meaning to influence, while ''effect'' is usually a noun meaning a result.","example":"The weather affects mood. The drug had side effects.","images":[]}',
         3, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Then/Than',
         '{"description":"Two words confused in comparisons and sequences","category":"Common Errors","difficulty":2,"popularity":80,"definition":"''Then'' refers to time or sequence; ''than'' is used for comparisons.","example":"I ate first, then left. She is taller than me.","images":[]}',
         2, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Lose/Loose',
         '{"description":"A pair of words often mixed up due to similar spelling","category":"Common Errors","difficulty":2,"popularity":75,"definition":"''Lose'' means to misplace or fail to win (pronounced looz), while ''loose'' means not tight (pronounced loos).","example":"Did you lose your wallet? This knot is too loose.","images":[]}',
         2, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'To/Too/Two',
         '{"description":"Three homophones with completely different uses","category":"Common Errors","difficulty":1,"popularity":90,"definition":"''To'' is a preposition, ''too'' means also or excessively, and ''two'' is the number 2.","example":"I went to the store too. I bought two apples.","images":[]}',
         1, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Accept/Except',
         '{"description":"A verb and preposition pair frequently confused","category":"Common Errors","difficulty":2,"popularity":75,"definition":"''Accept'' means to receive willingly, while ''except'' means excluding or other than.","example":"I accept your offer. Everyone came except John.","images":[]}',
         2, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Principle/Principal',
         '{"description":"A pair of nouns with different meanings often swapped","category":"Common Errors","difficulty":3,"popularity":75,"definition":"''Principle'' is a fundamental truth or rule; ''principal'' means main or the head of a school.","example":"Honesty is a key principle. The school principal gave a speech.","images":[]}',
         3, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Stationary/Stationery',
         '{"description":"A pair of adjectives and nouns confused due to identical pronunciation","category":"Common Errors","difficulty":3,"popularity":65,"definition":"''Stationary'' means not moving, while ''stationery'' refers to writing materials like paper and pens.","example":"The car remained stationary. I bought new stationery for school.","images":[]}',
         3, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Complement/Compliment',
         '{"description":"A pair of words with distinct meanings often misspelled","category":"Common Errors","difficulty":3,"popularity":65,"definition":"''Complement'' means something that completes or enhances, while ''compliment'' is an expression of praise.","example":"The wine complements the meal. She received a nice compliment.","images":[]}',
         3, ARRAY['concept', 'usage']),
        ('english_fundamentals', 'Disinterested/Uninterested',
         '{"description":"A pair of adjectives with different meanings often confused","category":"Common Errors","difficulty":4,"popularity":60,"definition":"''Disinterested'' means impartial or unbiased, while ''uninterested'' means not interested or bored.","example":"A judge must be disinterested. She was uninterested in the lecture.","images":[]}',
         4, ARRAY['concept', 'usage']),

        -- ── FIGURATIVE LANGUAGE (10) ─────────────────────────────────────
        ('english_fundamentals', 'Idiom',
         '{"description":"A fixed expression whose meaning is not deducible from its individual words","category":"Figurative Language","difficulty":3,"popularity":85,"definition":"An idiom is a conventional phrase with a figurative meaning that differs from its literal interpretation.","example":"Spill the beans, kick the bucket","contrast":"Proverb","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Proverb',
         '{"description":"A short, traditional saying that imparts wisdom or advice","category":"Figurative Language","difficulty":3,"popularity":80,"definition":"A proverb is a folk saying that expresses a universal truth or piece of practical wisdom.","example":"A stitch in time saves nine.","contrast":"Idiom","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Cliché',
         '{"description":"An overused expression that has lost its original impact","category":"Figurative Language","difficulty":2,"popularity":70,"definition":"A cliché is a phrase or idea that has become trite through excessive use and lacks originality.","example":"Think outside the box, at the end of the day","contrast":"Idiom","images":[]}',
         2, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Pun',
         '{"description":"A humorous play on words exploiting multiple meanings or similar sounds","category":"Figurative Language","difficulty":3,"popularity":75,"definition":"A pun uses words with multiple meanings or similar sounds to create a humorous or witty effect.","example":"I used to be a baker, but I couldn''t make enough dough.","contrast":"Irony","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Euphemism',
         '{"description":"A mild or indirect expression substituted for a harsh or blunt one","category":"Figurative Language","difficulty":3,"popularity":75,"definition":"A euphemism replaces a direct, unpleasant, or offensive term with a softer, more polite alternative.","example":"Passed away instead of died","contrast":"Hyperbole","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Understatement',
         '{"description":"Deliberately making a situation seem less important than it is","category":"Figurative Language","difficulty":3,"popularity":65,"definition":"An understatement minimizes the significance of an event for rhetorical effect, often for irony.","example":"It''s just a scratch — said after a car crash.","contrast":"Hyperbole","images":[]}',
         3, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Malapropism',
         '{"description":"The mistaken use of a word in place of a similar-sounding one with a different meaning","category":"Figurative Language","difficulty":4,"popularity":60,"definition":"A malapropism substitutes an incorrect word for a similar-sounding correct word, creating humorous nonsense.","example":"He is the pineapple of politeness (instead of pinnacle).","contrast":"Pun","images":[]}',
         4, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Synecdoche',
         '{"description":"A figure of speech where a part represents the whole or vice versa","category":"Figurative Language","difficulty":4,"popularity":60,"definition":"Synecdoche uses a part of something to refer to the whole, or the whole to represent a part.","example":"All hands on deck (hands meaning sailors).","contrast":"Metonymy","images":[]}',
         4, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Metonymy',
         '{"description":"Replacing the name of something with something closely associated with it","category":"Figurative Language","difficulty":4,"popularity":60,"definition":"Metonymy substitutes a related term for the thing itself.","example":"The White House issued a statement (meaning the US government).","contrast":"Synecdoche","images":[]}',
         4, ARRAY['concept', 'literary-devices']),
        ('english_fundamentals', 'Litotes',
         '{"description":"An ironic understatement expressed through negation of the opposite","category":"Figurative Language","difficulty":4,"popularity":55,"definition":"Litotes affirms something by negating its contrary, creating understated emphasis.","example":"She is not unfriendly (meaning she is friendly).","contrast":"Understatement","images":[]}',
         4, ARRAY['concept', 'literary-devices']);

    END IF;
